class FenwickTree2D:
    def __init__(self, matrix):
        self.rows = len(matrix)
        self.cols = len(matrix[0]) if self.rows > 0 else 0
        self.bit = [[0] * (self.cols + 1) for _ in range(self.rows + 1)]
        self.matrix_values = [[0] * self.cols for _ in range(self.rows)]

        for r in range(self.rows):
            for c in range(self.cols):
                diff = matrix[r][c]
                self.matrix_values[r][c] = matrix[r][c]

                r_idx = r + 1
                while r_idx <= self.rows:
                    c_idx = c + 1
                    while c_idx <= self.cols:
                        self.bit[r_idx][c_idx] += diff
                        c_idx += c_idx & -c_idx
                    r_idx += r_idx & -r_idx

    def update(self, row, col, new_val):
        diff = new_val - self.matrix_values[row][col]
        self.matrix_values[row][col] = new_val

        r_idx = row + 1
        while r_idx <= self.rows:
            c_idx = col + 1
            while c_idx <= self.cols:
                self.bit[r_idx][c_idx] += diff
                c_idx += c_idx & -c_idx
            r_idx += r_idx & -r_idx

    def _query_prefix_sum(self, r_idx, c_idx):
        total_sum = 0
        i = r_idx
        while i > 0:
            j = c_idx
            while j > 0:
                total_sum += self.bit[i][j]
                j -= j & -j
            i -= i & -i
        return total_sum

    def range_sum(self, r1, c1, r2, c2):
        sum_r2_c2 = self._query_prefix_sum(r2 + 1, c2 + 1)
        sum_r1_minus_1_c2 = self._query_prefix_sum(r1, c2 + 1)
        sum_r2_c1_minus_1 = self._query_prefix_sum(r2 + 1, c1)
        sum_r1_minus_1_c1_minus_1 = self._query_prefix_sum(r1, c1)

        return sum_r2_c2 - sum_r1_minus_1_c2 - sum_r2_c1_minus_1 + sum_r1_minus_1_c1_minus_1
